// ---------- Supabase: configuración y helpers ----------
const SUPABASE_URL = "https://ifbsithrlzsxtomsfyxi.supabase.co";
const SUPABASE_ANON_KEY = "sb_publishable_q5_NZC8iNB4KQ0I2x4y_Ww_r1u7F1gC";

async function sbFetch(path, token, options = {}) {
  const res = await fetch(`${SUPABASE_URL}${path}`, {
    ...options,
    headers: {
      apikey: SUPABASE_ANON_KEY,
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
      ...(options.method && options.method !== "GET" ? { Prefer: "return=representation" } : {}),
      ...options.headers,
    },
  });
  if (!res.ok) {
    let msg = res.statusText;
    try { const j = await res.json(); msg = j.message || j.msg || msg; } catch {}
    throw new Error(msg);
  }
  if (res.status === 204) return null;
  const text = await res.text();
  return text ? JSON.parse(text) : null;
}

async function signIn(email, password) {
  const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
    method: "POST",
    headers: { apikey: SUPABASE_ANON_KEY, "Content-Type": "application/json" },
    body: JSON.stringify({ email, password }),
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error_description || data.msg || "Correo o contraseña incorrectos");
  return data; // { access_token, refresh_token, user }
}

// Tablas que NO tienen columna created_at (no se debe ordenar por ella)
const NO_CREATED_AT = new Set(["app_state"]);
const apiList = (table, token, order) => {
  // Si no se especifica orden, usar created_at.desc salvo en tablas sin esa columna
  const ord = order === null ? "" : (order || (NO_CREATED_AT.has(table) ? "" : "created_at.desc"));
  return sbFetch(`/rest/v1/${table}?select=*${ord ? `&order=${ord}` : ""}`, token);
};
const apiInsert = (table, token, payload) => sbFetch(`/rest/v1/${table}`, token, { method: "POST", body: JSON.stringify(payload) }).then((r) => r[0]);
const apiUpdate = (table, token, id, payload) => sbFetch(`/rest/v1/${table}?id=eq.${id}`, token, { method: "PATCH", body: JSON.stringify(payload) }).then((r) => r[0]);
const apiDelete = (table, token, id) => sbFetch(`/rest/v1/${table}?id=eq.${id}`, token, { method: "DELETE" });

// ---------- Transformaciones JS (camelCase) <-> DB (snake_case) ----------
const T = {
  account: {
    from: (r) => ({ id: r.id, name: r.name, type: r.type, initialBalance: Number(r.initial_balance) }),
    to: (a) => ({ name: a.name, type: a.type, initial_balance: a.initialBalance ?? 0 }),
  },
  category: {
    from: (r) => ({ id: r.id, name: r.name, limit: Number(r.limit), icon: r.icon, color: r.color }),
    to: (c) => ({ name: c.name, limit: c.limit ?? 0, icon: c.icon, color: c.color }),
  },
  debt: {
    from: (r) => ({ id: r.id, name: r.name, accountId: r.account_id, proyectado: Number(r.proyectado) }),
    to: (d) => ({ name: d.name, account_id: d.accountId, proyectado: d.proyectado ?? 0 }),
  },
  goal: {
    from: (r) => ({ id: r.id, name: r.name, accountId: r.account_id, proyectado: Number(r.proyectado) }),
    to: (g) => ({ name: g.name, account_id: g.accountId, proyectado: g.proyectado ?? 0 }),
  },
  movement: {
    from: (r) => ({ id: r.id, kind: r.kind, amount: Number(r.amount), date: r.date, note: r.note || "", accountId: r.account_id, categoryId: r.category_id, debtId: r.debt_id, goalId: r.goal_id }),
    to: (m) => ({ kind: m.kind, amount: m.amount, date: m.date, note: m.note || "", account_id: m.accountId, category_id: m.categoryId || null, debt_id: m.debtId || null, goal_id: m.goalId || null }),
  },
};

const TABLE_BY_KEY = { accounts: "accounts", categories: "categories", debts: "debts", goals: "goals" };
const T_BY_KEY = { accounts: T.account, categories: T.category, debts: T.debt, goals: T.goal };

const EMPTY_STATE = {
  accounts: [],
  categories: [],
  debts: [],
  goals: [],
  movements: [],
  streak: { count: 0, lastDate: null },
};

export default function App() {
  const [session, setSession] = useState(null); // { accessToken, email }
  const [authError, setAuthError] = useState(null);
  const [authLoading, setAuthLoading] = useState(false);

  const [state, setState] = useState(EMPTY_STATE);
  const [loaded, setLoaded] = useState(false);
  const [syncError, setSyncError] = useState(null);
  const [tab, setTab] = useState("home");
  const [activeModule, setActiveModule] = useState(null); // null = pantalla de módulos
  const [showForm, setShowForm] = useState(false);
  const [showCatManager, setShowCatManager] = useState(false);
  const [showAccManager, setShowAccManager] = useState(false);
  const [showDebtManager, setShowDebtManager] = useState(false);
  const [showGoalManager, setShowGoalManager] = useState(false);
  const [toast, setToast] = useState(null);

  async function handleLogin(email, password) {
    setAuthLoading(true);
    setAuthError(null);
    try {
      const data = await signIn(email, password);
      setSession({ accessToken: data.access_token, email: data.user?.email || email });
    } catch (e) {
      setAuthError(e.message);
    } finally {
      setAuthLoading(false);
    }
  }
  function handleLogout() {
    setSession(null);
    setState(EMPTY_STATE);
    setLoaded(false);
  }

  useEffect(() => {
    if (!session) return;
    (async () => {
      const token = session.accessToken;
      // Cada tabla se carga de forma independiente: si una falla, las demás
      // siguen disponibles y NO se pierde el histórico ni se fuerza el setup.
      const safe = async (fn) => { try { return await fn(); } catch (e) { console.error(e); return null; } };
      const [accs, cats, debts, goals, movs, appStateRows] = await Promise.all([
        safe(() => apiList("accounts", token)),
        safe(() => apiList("categories", token)),
        safe(() => apiList("debts", token)),
        safe(() => apiList("goals", token)),
        safe(() => apiList("movements", token)),
        safe(() => apiList("app_state", token)),
      ]);
      const appRow = appStateRows?.[0];
      const failed = [accs, cats, debts, goals, movs].some((r) => r === null);
      if (failed) setSyncError("Algunos datos no cargaron. Revisa tu conexión.");
      setState({
        accounts: (accs || []).map(T.account.from),
        categories: (cats || []).map(T.category.from),
        debts: (debts || []).map(T.debt.from),
        goals: (goals || []).map(T.goal.from),
        movements: (movs || []).map(T.movement.from),
        streak: appRow ? { count: appRow.streak_count, lastDate: appRow.streak_last_date } : { count: 0, lastDate: null },
      });
      setLoaded(true);
    })();
  }, [session]);

  // ---- Derivados ----
  const accountBalances = useMemo(() => {
    const map = {};
    state.accounts.forEach((a) => (map[a.id] = a.initialBalance || 0));
    state.movements.forEach((m) => {
      if (!map.hasOwnProperty(m.accountId)) return;
      if (m.kind === "ingreso") map[m.accountId] += m.amount;
      else map[m.accountId] -= m.amount;
    });
    return map;
  }, [state.accounts, state.movements]);
  const totalBalance = Object.values(accountBalances).reduce((s, v) => s + v, 0);

  const debtPaidTotal = useMemo(() => {
    const map = {};
    state.debts.forEach((d) => (map[d.id] = 0));
    state.movements.forEach((m) => { if (m.kind === "pago_deuda" && map.hasOwnProperty(m.debtId)) map[m.debtId] += m.amount; });
    return map;
  }, [state.debts, state.movements]);
  const debtPaidThisMonth = useMemo(() => {
    const map = {};
    state.debts.forEach((d) => (map[d.id] = 0));
    state.movements.forEach((m) => { if (m.kind === "pago_deuda" && monthKey(m.date) === thisMonthKey() && map.hasOwnProperty(m.debtId)) map[m.debtId] += m.amount; });
    return map;
  }, [state.debts, state.movements]);

  const goalSavedTotal = useMemo(() => {
    const map = {};
    state.goals.forEach((g) => (map[g.id] = 0));
    state.movements.forEach((m) => { if (m.kind === "aporte_ahorro" && map.hasOwnProperty(m.goalId)) map[m.goalId] += m.amount; });
    return map;
  }, [state.goals, state.movements]);

  const currentMonthSpentByCategory = useMemo(() => {
    const map = {};
    state.categories.forEach((c) => (map[c.id] = 0));
    state.movements.forEach((m) => {
      if (m.kind === "gasto" && monthKey(m.date) === thisMonthKey() && map.hasOwnProperty(m.categoryId)) map[m.categoryId] += m.amount;
    });
    return map;
  }, [state.categories, state.movements]);

  const totalProyectado = useMemo(() => state.categories.reduce((s, c) => s + (c.limit || 0), 0), [state.categories]);
  const totalRealMes = useMemo(() => Object.values(currentMonthSpentByCategory).reduce((s, v) => s + v, 0), [currentMonthSpentByCategory]);
  const currentMonthIncome = useMemo(() => state.movements.filter((m) => m.kind === "ingreso" && monthKey(m.date) === thisMonthKey()).reduce((s, m) => s + m.amount, 0), [state.movements]);

  const pctUsed = totalProyectado > 0 ? totalRealMes / totalProyectado : 0;
  const mood = totalProyectado === 0 ? "happy" : pctUsed < 0.7 ? "happy" : pctUsed < 1 ? "sad" : "angry";
  const overBudgetCats = state.categories.filter((c) => c.limit > 0 && (currentMonthSpentByCategory[c.id] || 0) > c.limit);

  function notify(msg) { setToast(msg); setTimeout(() => setToast(null), 2200); }

  // ---- Movimientos (van directo contra Supabase) ----
  async function addMovement(m) {
    const token = session.accessToken;
    try {
      const row = await apiInsert("movements", token, T.movement.to({ ...m, date: m.date || todayStr() }));
      const item = T.movement.from(row);
      setState((s) => ({ ...s, movements: [item, ...s.movements] }));

      const today = todayStr();
      if (state.streak.lastDate !== today) {
        const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
        const newCount = state.streak.lastDate === yesterday ? state.streak.count + 1 : 1;
        await apiUpdate("app_state", token, 1, { streak_count: newCount, streak_last_date: today });
        setState((s) => ({ ...s, streak: { count: newCount, lastDate: today } }));
      }
      setShowForm(false);
      const labels = { gasto: "¡Gasto registrado! 🐾", ingreso: "¡Ingreso registrado! 🐾", pago_deuda: "¡Pago registrado! 🐾", aporte_ahorro: "¡Aporte registrado! 🐾" };
      notify(labels[m.kind]);
    } catch (e) {
      notify("⚠️ No se pudo guardar: " + e.message);
    }
  }
  async function removeMovement(id) {
    try {
      await apiDelete("movements", session.accessToken, id);
      setState((s) => ({ ...s, movements: s.movements.filter((m) => m.id !== id) }));
    } catch (e) {
      notify("⚠️ No se pudo borrar: " + e.message);
    }
  }

  // ---- Setter genérico para cuentas/categorías/deudas/metas ----
  // Detecta add/editar/borrar comparando el arreglo anterior con el nuevo,
  // y sincroniza esa diferencia contra Supabase, manteniendo la misma firma
  // (setX(prev => next)) que ya usan los modales de gestión.
  function makeEntitySetter(stateKey) {
    const table = TABLE_BY_KEY[stateKey];
    const transform = T_BY_KEY[stateKey];
    return function (fn) {
      const token = session.accessToken;
      const prev = state[stateKey];
      const next = typeof fn === "function" ? fn(prev) : fn;
      setState((s) => ({ ...s, [stateKey]: next }));

      (async () => {
        try {
          if (next.length > prev.length) {
            const added = next.filter((n) => !prev.some((p) => p.id === n.id));
            for (const item of added) {
              const row = await apiInsert(table, token, transform.to(item));
              const real = transform.from(row);
              setState((s) => ({ ...s, [stateKey]: s[stateKey].map((x) => x.id === item.id ? real : x) }));
            }
          } else if (next.length < prev.length) {
            const removed = prev.filter((p) => !next.some((n) => n.id === p.id));
            for (const item of removed) await apiDelete(table, token, item.id);
          } else {
            for (const item of next) {
              const old = prev.find((p) => p.id === item.id);
              if (old && JSON.stringify(old) !== JSON.stringify(item)) {
                await apiUpdate(table, token, item.id, transform.to(item));
              }
            }
          }
        } catch (e) {
          notify("⚠️ No se pudo sincronizar: " + e.message);
        }
      })();
    };
  }
  const setCategories = makeEntitySetter("categories");
  const setAccounts = makeEntitySetter("accounts");
  const setDebts = makeEntitySetter("debts");
  const setGoals = makeEntitySetter("goals");

  async function completeSetup(accs) {
    const token = session.accessToken;
    try {
      const inserted = [];
      for (const a of accs) inserted.push(T.account.from(await apiInsert("accounts", token, T.account.to(a))));
      let defaultCats = state.categories;
      if (defaultCats.length === 0) {
        defaultCats = [];
        for (const c of DEFAULT_CATEGORIES) defaultCats.push(T.category.from(await apiInsert("categories", token, T.category.to(c))));
      }
      setState((s) => ({ ...s, accounts: inserted, categories: defaultCats }));
    } catch (e) {
      notify("⚠️ Error al configurar: " + e.message);
    }
  }

  if (!session) {
    return (
      <div style={styles.app}>
        <FontLoader />
        <div style={styles.phoneFrame}>
          <LoginView onLogin={handleLogin} loading={authLoading} error={authError} />
        </div>
      </div>
    );
  }

  if (!loaded) {
    return <div style={{ ...styles.app, alignItems: "center", justifyContent: "center" }}><div style={{ color: PALETTE.inkSoft }}>Cargando...</div></div>;
  }

  return (
    <div style={styles.app}>
      <FontLoader />
      <div style={styles.phoneFrame}>
        {syncError && <div style={{ ...styles.toast, background: PALETTE.orange, top: 10 }}>⚠️ {syncError}</div>}
        {activeModule === null ? (
          <ModulesHome onOpen={(m) => { setActiveModule(m); setTab("home"); }}
            onLogout={handleLogout} userEmail={session.email} />
        ) : (
          <>
            {tab === "home" && (
              <HomeView accounts={state.accounts} accountBalances={accountBalances} totalBalance={totalBalance}
                streak={state.streak} categories={state.categories} spentByCategory={currentMonthSpentByCategory}
                overBudgetCats={overBudgetCats} movements={state.movements} debts={state.debts} goals={state.goals}
                totalProyectado={totalProyectado} totalRealMes={totalRealMes} currentMonthIncome={currentMonthIncome}
                onOpenAccounts={() => setShowAccManager(true)} onBack={() => setActiveModule(null)} onLogout={handleLogout} userEmail={session.email} />
            )}
            {tab === "presupuesto" && (
              <PresupuestoView categories={state.categories} spent={currentMonthSpentByCategory}
                totalProyectado={totalProyectado} totalRealMes={totalRealMes}
                onManage={() => setShowCatManager(true)} />
            )}
            {tab === "deudas" && (
              <DeudasView debts={state.debts} accounts={state.accounts} paidTotal={debtPaidTotal} paidMonth={debtPaidThisMonth}
                onManage={() => setShowDebtManager(true)} />
            )}
            {tab === "ahorros" && (
              <AhorrosView goals={state.goals} accounts={state.accounts} saved={goalSavedTotal}
                onManage={() => setShowGoalManager(true)} />
            )}
            {tab === "historial" && (
              <HistorialView movements={state.movements} accounts={state.accounts} categories={state.categories}
                debts={state.debts} goals={state.goals} onRemove={removeMovement} />
            )}

            <button style={styles.fab} onClick={() => setShowForm(true)} aria-label="Registrar movimiento">
              <Plus size={26} color="#fff" strokeWidth={2.5} />
            </button>

            <NavBar tab={tab} setTab={setTab} />

            {showForm && (
              <TransactionForm categories={state.categories} accounts={state.accounts} debts={state.debts} goals={state.goals}
                onClose={() => setShowForm(false)} onSubmit={addMovement} />
            )}
            {showCatManager && (
              <CategoryManager categories={state.categories} setCategories={setCategories} onClose={() => setShowCatManager(false)} />
            )}
            {showAccManager && (
              <AccountManager accounts={state.accounts} setAccounts={setAccounts} onClose={() => setShowAccManager(false)} />
            )}
            {showDebtManager && (
              <DebtManager debts={state.debts} accounts={state.accounts} setDebts={setDebts} onClose={() => setShowDebtManager(false)} />
            )}
            {showGoalManager && (
              <GoalManager goals={state.goals} accounts={state.accounts} setGoals={setGoals} onClose={() => setShowGoalManager(false)} />
            )}
            {toast && <div style={styles.toast}>{toast}</div>}
          </>
        )}
      </div>
    </div>
  );
}

function FontLoader() {
  useEffect(() => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://fonts.googleapis.com/css2?family=Bagel+Fat+One&family=Nunito:wght@400;600;700;800&display=swap";
    document.head.appendChild(link);
    return () => document.head.removeChild(link);
  }, []);
  return null;
}

// ---------- Login ----------
function LoginView({ onLogin, loading, error }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  function submit() {
    if (!email.trim() || !password) return;
    onLogin(email.trim(), password);
  }

  return (
    <div style={styles.scroll}>
      <div style={{ padding: "60px 24px 20px", textAlign: "center" }}>
        <div style={{ display: "flex", justifyContent: "center", gap: 10, marginBottom: 14 }}>
          <Familia size={150} />
        </div>
        <div style={styles.eyebrow}>Gestión del hogar de</div>
        <h1 style={styles.h1}>Blu &amp; Rembe</h1>
      </div>

      <div style={{ padding: "0 20px" }}>
        <div style={styles.setupCard}>
          <div style={styles.fieldLabel}>Correo</div>
          <input style={styles.textInput} type="email" value={email} onChange={(e) => setEmail(e.target.value)}
            placeholder="tucorreo@ejemplo.com" onKeyDown={(e) => e.key === "Enter" && submit()} />
          <div style={{ ...styles.fieldLabel, marginTop: 10 }}>Contraseña</div>
          <input style={styles.textInput} type="password" value={password} onChange={(e) => setPassword(e.target.value)}
            placeholder="••••••••" onKeyDown={(e) => e.key === "Enter" && submit()} />
        </div>

        {error && (
          <div style={{ ...styles.alertCard, margin: "0 0 14px" }}>
            <Sparkles size={16} color={PALETTE.crimson} />
            <div style={{ fontSize: 13, color: PALETTE.crimson, fontWeight: 700 }}>{error}</div>
          </div>
        )}

        <button disabled={loading} onClick={submit} style={{ ...styles.submitBtn, opacity: loading ? 0.6 : 1 }}>
          <Check size={18} color="#fff" />
          {loading ? "Entrando..." : "Entrar"}
        </button>
      </div>
    </div>
  );
}

// ---------- Setup ----------
function SetupView({ onComplete }) {
  const [accs, setAccs] = useState([{ id: genId(), name: "Cuenta 1", type: "ahorro", initialBalance: "" }]);

  function update(id, patch) { setAccs((prev) => prev.map((a) => a.id === id ? { ...a, ...patch } : a)); }
  function addRow() { setAccs((prev) => [...prev, { id: genId(), name: `Cuenta ${prev.length + 1}`, type: "ahorro", initialBalance: "" }]); }
  function removeRow(id) { setAccs((prev) => prev.filter((a) => a.id !== id)); }

  return (
    <div style={styles.scroll}>
      <div style={{ padding: "36px 24px 16px", textAlign: "center" }}>
        <div style={{ display: "flex", justifyContent: "center", gap: 10, marginBottom: 14 }}>
          <Familia size={130} />
        </div>
        <div style={styles.eyebrow}>Casa BeBe</div>
        <h1 style={styles.h1}>Empecemos</h1>
        <div style={{ fontSize: 13, color: PALETTE.inkSoft, fontWeight: 600, marginTop: 6 }}>
          Cuéntanos qué cuentas tienen hoy (ahorros o tarjetas) y cuánto hay en cada una
        </div>
      </div>

      <div style={{ padding: "0 20px 20px" }}>
        {accs.map((a, i) => (
          <div key={a.id} style={styles.setupCard}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div style={styles.fieldLabel}>Cuenta {i + 1}</div>
              {accs.length > 1 && <button onClick={() => removeRow(a.id)} style={styles.iconBtn}><Trash2 size={15} color={PALETTE.crimson} /></button>}
            </div>
            <input style={styles.textInput} value={a.name} onChange={(e) => update(a.id, { name: e.target.value })} placeholder="Nombre" />
            <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
              <button onClick={() => update(a.id, { type: "ahorro" })} style={{ ...styles.typeToggle, flex: 1, background: a.type === "ahorro" ? PALETTE.pear : "#fff", color: a.type === "ahorro" ? "#fff" : PALETTE.ink }}>Ahorro</button>
              <button onClick={() => update(a.id, { type: "credito" })} style={{ ...styles.typeToggle, flex: 1, background: a.type === "credito" ? PALETTE.sienna : "#fff", color: a.type === "credito" ? "#fff" : PALETTE.ink }}>Tarjeta crédito</button>
            </div>
            <div style={{ ...styles.fieldLabel, marginTop: 10 }}>Saldo actual</div>
            <input style={styles.amountInput} type="number" inputMode="numeric" placeholder="0"
              value={a.initialBalance} onChange={(e) => update(a.id, { initialBalance: e.target.value })} />
          </div>
        ))}

        <button onClick={addRow} style={{ ...styles.manageBtn, width: "100%", justifyContent: "center", marginBottom: 16 }}>
          <Plus size={16} color={PALETTE.crimson} />
          <span style={{ fontSize: 13, fontWeight: 800, color: PALETTE.crimson }}>Agregar otra cuenta</span>
        </button>

        <button style={styles.submitBtn} onClick={() => onComplete(accs.map((a) => ({
          id: a.id, name: a.name || "Cuenta", type: a.type, initialBalance: Number(a.initialBalance) || 0,
        })))}>
          <Check size={18} color="#fff" />
          Empezar a registrar
        </button>
        <div style={{ fontSize: 12, color: PALETTE.inkSoft, textAlign: "center", marginTop: 10, marginBottom: 30 }}>
          Todo el historial se guarda para siempre, mes tras mes
        </div>
      </div>
    </div>
  );
}

