// ---------- Historial ----------
function HistorialView({ movements, accounts, categories, debts, goals, onRemove }) {
  const [filterMonth, setFilterMonth] = useState("");
  const kindIcon = { gasto: ArrowDownCircle, ingreso: ArrowUpCircle, pago_deuda: CreditCard, aporte_ahorro: PiggyBank };
  const kindColor = { gasto: PALETTE.orange, ingreso: PALETTE.sage, pago_deuda: PALETTE.grape, aporte_ahorro: PALETTE.lilac };
  const kindLabel = { gasto: "Gasto", ingreso: "Ingreso", pago_deuda: "Pago deuda", aporte_ahorro: "Aporte ahorro" };
  const accName = (id) => accounts.find((a) => a.id === id)?.name || "—";
  const detailFor = (m) => {
    if (m.kind === "gasto") return categories.find((c) => c.id === m.categoryId)?.name || "—";
    if (m.kind === "pago_deuda") return debts.find((d) => d.id === m.debtId)?.name || "—";
    if (m.kind === "aporte_ahorro") return goals.find((g) => g.id === m.goalId)?.name || "—";
    return "—";
  };
  const filtered = filterMonth ? movements.filter((m) => monthKey(m.date) === filterMonth) : movements;

  return (
    <div style={styles.scroll}>
      <div style={{ padding: "20px 20px 4px" }}>
        <h1 style={styles.h1}>Historial</h1>
      </div>
      <div style={{ padding: "0 20px" }}>
        <input type="month" value={filterMonth} onChange={(e) => setFilterMonth(e.target.value)} style={{ ...styles.textInput, marginBottom: 12 }} />
        {filtered.length === 0 && <Empty>Sin movimientos.</Empty>}
        {filtered.map((m) => {
          const Icon = kindIcon[m.kind];
          return (
            <div key={m.id} style={styles.expenseRow}>
              <div style={{ ...styles.iconCircle, background: kindColor[m.kind] + "22" }}><Icon size={16} color={kindColor[m.kind]} /></div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 14 }}>{kindLabel[m.kind]} · {detailFor(m)}</div>
                <div style={{ fontSize: 12, color: PALETTE.inkSoft }}>{m.date} · {accName(m.accountId)}{m.note ? ` · ${m.note}` : ""}</div>
              </div>
              <div style={{ fontWeight: 800, fontSize: 14, color: m.kind === "ingreso" ? PALETTE.pear : PALETTE.ink, marginRight: 4 }}>
                {m.kind === "ingreso" ? "+" : "-"}{fmt(m.amount)}
              </div>
              <button onClick={() => onRemove(m.id)} style={styles.iconBtn}><Trash2 size={14} color={PALETTE.inkSoft} /></button>
            </div>
          );
        })}
        <div style={{ height: 90 }} />
      </div>
    </div>
  );
}

// ---------- Formulario de transacción ----------
function TransactionForm({ categories, accounts, debts, goals, onClose, onSubmit }) {
  const [kind, setKind] = useState("gasto");
  const [amount, setAmount] = useState("");
  const [categoryId, setCategoryId] = useState(categories[0]?.id || "");
  const [debtId, setDebtId] = useState(debts[0]?.id || "");
  const [goalId, setGoalId] = useState(goals[0]?.id || "");
  const [accountId, setAccountId] = useState(accounts[0]?.id || "");
  const [note, setNote] = useState("");
  const [date, setDate] = useState(todayStr());

  const kindColor = { gasto: PALETTE.orange, ingreso: PALETTE.sage, pago_deuda: PALETTE.grape, aporte_ahorro: PALETTE.lilac };
  const canSubmit = amount && Number(amount) > 0 && accountId
    && (kind !== "gasto" || categoryId) && (kind !== "pago_deuda" || debtId) && (kind !== "aporte_ahorro" || goalId);

  function submit() {
    onSubmit({ kind, amount: Number(amount), accountId, note, date,
      categoryId: kind === "gasto" ? categoryId : null,
      debtId: kind === "pago_deuda" ? debtId : null,
      goalId: kind === "aporte_ahorro" ? goalId : null,
    });
  }

  return (
    <div style={styles.modalOverlay} onClick={onClose}>
      <div style={styles.modalSheet} onClick={(e) => e.stopPropagation()}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div style={{ fontWeight: 800, fontSize: 17, fontFamily: "'Bagel Fat One', 'Trebuchet MS', sans-serif" }}>Nuevo movimiento</div>
          <button onClick={onClose} style={styles.iconBtn}><X size={20} color={PALETTE.inkSoft} /></button>
        </div>

        <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 6 }}>
          {[["gasto", "Gasto"], ["ingreso", "Ingreso"], ["pago_deuda", "Pago deuda"], ["aporte_ahorro", "Aporte ahorro"]].map(([k, label]) => (
            <button key={k} onClick={() => setKind(k)} style={{ ...styles.typeToggle, flex: "1 1 45%", background: kind === k ? kindColor[k] : "#fff", color: kind === k ? "#fff" : PALETTE.ink }}>
              {label}
            </button>
          ))}
        </div>

        <div style={styles.fieldLabel}>Monto</div>
        <MoneyInput value={amount} onChange={(v) => setAmount(v)} placeholder="$ 0" style={styles.amountInput} />

        <div style={styles.fieldLabel}>Cuenta</div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
          {accounts.map((a) => {
            const active = accountId === a.id;
            return (
              <button key={a.id} onClick={() => setAccountId(a.id)} style={{ ...styles.catChip, background: active ? PALETTE.crimson : "#fff", borderColor: PALETTE.crimson }}>
                <span style={{ color: active ? "#fff" : PALETTE.ink, fontSize: 12, fontWeight: 700 }}>{a.name}</span>
              </button>
            );
          })}
          {accounts.length === 0 && <div style={{ fontSize: 12, color: PALETTE.inkSoft }}>Agrega una cuenta primero.</div>}
        </div>

        {kind === "gasto" && (
          <>
            <div style={styles.fieldLabel}>Categoría</div>
            <div style={styles.catGrid}>
              {categories.map((c) => {
                const Icon = ICONS[c.icon] || Tag;
                const active = categoryId === c.id;
                return (
                  <button key={c.id} onClick={() => setCategoryId(c.id)} style={{ ...styles.catChip, background: active ? c.color : "#fff", borderColor: c.color }}>
                    <Icon size={14} color={active ? "#fff" : c.color} />
                    <span style={{ color: active ? "#fff" : PALETTE.ink, fontSize: 12, fontWeight: 700 }}>{c.name}</span>
                  </button>
                );
              })}
            </div>
          </>
        )}

        {kind === "pago_deuda" && (
          <>
            <div style={styles.fieldLabel}>Deuda</div>
            <div style={styles.catGrid}>
              {debts.map((d) => {
                const active = debtId === d.id;
                return (
                  <button key={d.id} onClick={() => setDebtId(d.id)} style={{ ...styles.catChip, background: active ? PALETTE.sienna : "#fff", borderColor: PALETTE.sienna }}>
                    <span style={{ color: active ? "#fff" : PALETTE.ink, fontSize: 12, fontWeight: 700 }}>{d.name}</span>
                  </button>
                );
              })}
              {debts.length === 0 && <div style={{ fontSize: 12, color: PALETTE.inkSoft }}>Agrega una deuda primero en la pestaña Deudas.</div>}
            </div>
          </>
        )}

        {kind === "aporte_ahorro" && (
          <>
            <div style={styles.fieldLabel}>Meta</div>
            <div style={styles.catGrid}>
              {goals.map((g) => {
                const active = goalId === g.id;
                return (
                  <button key={g.id} onClick={() => setGoalId(g.id)} style={{ ...styles.catChip, background: active ? PALETTE.arctic : "#fff", borderColor: PALETTE.arctic }}>
                    <span style={{ color: active ? PALETTE.ink : PALETTE.ink, fontSize: 12, fontWeight: 700 }}>{g.name}</span>
                  </button>
                );
              })}
              {goals.length === 0 && <div style={{ fontSize: 12, color: PALETTE.inkSoft }}>Agrega una meta primero en la pestaña Ahorros.</div>}
            </div>
          </>
        )}

        <div style={styles.fieldLabel}>Nota (opcional)</div>
        <input type="text" value={note} onChange={(e) => setNote(e.target.value)} placeholder="Ej: Rappi almuerzo" style={styles.textInput} />

        <div style={styles.fieldLabel}>Fecha</div>
        <input type="date" value={date} onChange={(e) => setDate(e.target.value)} style={styles.textInput} />

        <button disabled={!canSubmit} onClick={submit} style={{ ...styles.submitBtn, background: kindColor[kind], opacity: canSubmit ? 1 : 0.5 }}>
          <Check size={18} color="#fff" />
          Registrar
        </button>
      </div>
    </div>
  );
}

// ---------- Gestor de Categorías ----------
function CategoryManager({ categories, setCategories, onClose }) {
  const [editing, setEditing] = useState(null);
  const [name, setName] = useState("");
  const [limit, setLimit] = useState("");
  const [icon, setIcon] = useState("tag");

  function startEdit(c) { setEditing(c.id); setName(c.name); setLimit(c.limit > 0 ? String(c.limit) : ""); setIcon(c.icon); }
  function startNew() { setEditing("new"); setName(""); setLimit(""); setIcon("tag"); }
  function save() {
    if (!name.trim()) return;
    if (editing === "new") {
      const color = CAT_COLORS[categories.length % CAT_COLORS.length];
      setCategories((prev) => [...prev, { id: genId(), name: name.trim(), limit: Number(limit) || 0, icon, color }]);
    } else {
      setCategories((prev) => prev.map((c) => c.id === editing ? { ...c, name: name.trim(), limit: Number(limit) || 0, icon } : c));
    }
    setEditing(null);
  }
  function remove(id) { setCategories((prev) => prev.filter((c) => c.id !== id)); if (editing === id) setEditing(null); }

  return (
    <div style={styles.modalOverlay} onClick={onClose}>
      <div style={styles.modalSheet} onClick={(e) => e.stopPropagation()}>
        <ModalHeader title="Categorías" onClose={onClose} />
        {!editing && (
          <>
            {categories.map((c) => {
              const Icon = ICONS[c.icon] || Tag;
              return (
                <div key={c.id} style={{ ...styles.expenseRow, margin: "0 0 8px" }}>
                  <div style={{ ...styles.iconCircle, background: c.color + "22" }}><Icon size={16} color={c.color} /></div>
                  <div style={{ flex: 1, fontWeight: 700, fontSize: 14 }}>{c.name}</div>
                  <button onClick={() => startEdit(c)} style={styles.iconBtn}><Pencil size={16} color={PALETTE.inkSoft} /></button>
                  <button onClick={() => remove(c.id)} style={styles.iconBtn}><Trash2 size={16} color={PALETTE.crimson} /></button>
                </div>
              );
            })}
            <button style={{ ...styles.submitBtn, marginTop: 10 }} onClick={startNew}><Plus size={18} color="#fff" />Nueva categoría</button>
          </>
        )}
        {editing && (
          <>
            <div style={styles.fieldLabel}>Nombre</div>
            <input style={styles.textInput} value={name} onChange={(e) => setName(e.target.value)} placeholder="Ej: Educación" />
            <div style={styles.fieldLabel}>Presupuesto mensual (opcional)</div>
            <MoneyInput value={limit} onChange={(v) => setLimit(v)} placeholder="$ 0" style={styles.textInput} />
            <div style={styles.fieldLabel}>Ícono</div>
            <div style={styles.catGrid}>
              {ICON_KEYS.map((k) => {
                const Icon = ICONS[k]; const active = icon === k;
                return <button key={k} onClick={() => setIcon(k)} style={{ ...styles.iconChip, background: active ? PALETTE.crimson : "#fff", borderColor: PALETTE.crimson }}><Icon size={16} color={active ? "#fff" : PALETTE.crimson} /></button>;
              })}
            </div>
            <ModalActions onCancel={() => setEditing(null)} onSave={save} />
          </>
        )}
      </div>
    </div>
  );
}

// ---------- Gestor de Cuentas ----------
function AccountManager({ accounts, setAccounts, onClose }) {
  const [editing, setEditing] = useState(null);
  const [name, setName] = useState("");
  const [type, setType] = useState("ahorro");
  const [balance, setBalance] = useState("");

  function startEdit(a) { setEditing(a.id); setName(a.name); setType(a.type); setBalance(String(a.initialBalance)); }
  function startNew() { setEditing("new"); setName(""); setType("ahorro"); setBalance(""); }
  function save() {
    if (!name.trim()) return;
    if (editing === "new") {
      setAccounts((prev) => [...prev, { id: genId(), name: name.trim(), type, initialBalance: Number(balance) || 0 }]);
    } else {
      setAccounts((prev) => prev.map((a) => a.id === editing ? { ...a, name: name.trim(), type } : a));
    }
    setEditing(null);
  }
  function remove(id) { setAccounts((prev) => prev.filter((a) => a.id !== id)); if (editing === id) setEditing(null); }

  return (
    <div style={styles.modalOverlay} onClick={onClose}>
      <div style={styles.modalSheet} onClick={(e) => e.stopPropagation()}>
        <ModalHeader title="Cuentas" onClose={onClose} />
        {!editing && (
          <>
            {accounts.map((a) => (
              <div key={a.id} style={{ ...styles.expenseRow, margin: "0 0 8px" }}>
                <div style={{ ...styles.iconCircle, background: PALETTE.arctic + "55" }}>{a.type === "credito" ? <CreditCard size={16} color={PALETTE.crimson} /> : <Wallet size={16} color={PALETTE.crimson} />}</div>
                <div style={{ flex: 1, fontWeight: 700, fontSize: 14 }}>{a.name}</div>
                <button onClick={() => startEdit(a)} style={styles.iconBtn}><Pencil size={16} color={PALETTE.inkSoft} /></button>
                <button onClick={() => remove(a.id)} style={styles.iconBtn}><Trash2 size={16} color={PALETTE.crimson} /></button>
              </div>
            ))}
            <button style={{ ...styles.submitBtn, marginTop: 10 }} onClick={startNew}><Plus size={18} color="#fff" />Nueva cuenta</button>
          </>
        )}
        {editing && (
          <>
            <div style={styles.fieldLabel}>Nombre</div>
            <input style={styles.textInput} value={name} onChange={(e) => setName(e.target.value)} placeholder="Ej: Nequi" />
            <div style={{ display: "flex", gap: 8, marginTop: 10 }}>
              <button onClick={() => setType("ahorro")} style={{ ...styles.typeToggle, flex: 1, background: type === "ahorro" ? PALETTE.pear : "#fff", color: type === "ahorro" ? "#fff" : PALETTE.ink }}>Ahorro</button>
              <button onClick={() => setType("credito")} style={{ ...styles.typeToggle, flex: 1, background: type === "credito" ? PALETTE.sienna : "#fff", color: type === "credito" ? "#fff" : PALETTE.ink }}>Tarjeta</button>
            </div>
            {editing === "new" && (
              <>
                <div style={styles.fieldLabel}>Saldo inicial</div>
                <MoneyInput value={balance} onChange={(v) => setBalance(v)} placeholder="$ 0" style={styles.textInput} />
              </>
            )}
            <ModalActions onCancel={() => setEditing(null)} onSave={save} />
          </>
        )}
      </div>
    </div>
  );
}

